const test=require('node:test');const assert=require('node:assert/strict');const {managedUsersFromEnv,validateManagedUser}=require('../../src/utils/managedUsers');
test('construye psicóloga y mantenimiento con roles separados',()=>{const users=managedUsersFromEnv({PSYCHOLOGIST_EMAIL:'PSICOLOGA@EXAMPLE.COM',PSYCHOLOGIST_PASSWORD:'Psicologa123!',MAINTENANCE_EMAIL:'MANTTO@EXAMPLE.COM',MAINTENANCE_PASSWORD:'Mantenimiento123!'});assert.deepEqual(users.map(x=>x.rol),['psicologa','superadmin']);assert.equal(users[0].email,'psicologa@example.com');assert.equal(users[1].email,'mantto@example.com')});
test('rechaza contraseñas débiles y correos inválidos',()=>{assert.throws(()=>validateManagedUser({email:'incorrecto',password:'1234567890',rol:'superadmin'}),/Correo inválido/);assert.throws(()=>validateManagedUser({email:'ok@example.com',password:'corta',rol:'psicologa'}),/10 caracteres/)});
